#include<bits/stdc++.h>
using namespace std;
const int N = 2e5+5;
long long T,n,r[N],c[N],ans1,ans2,ans3,s[N];
long long r1,l2;
int main(){
    cin>>T;
    while(T--){
        cin>>n;
        r1=n,l2=1;
        for(int i=1;i<=n;i++)cin>>r[i];
        for(int i=1;i<=n;i++){cin>>c[i];s[i]=s[i-1]+abs(c[i]);if(c[i]>=0) { l2=i+1; }}
        for(int i=1;i<=n;i++)if(c[i]<0) { r1=i-1;break; }
        ans1=0,ans3=0;
        for(int i=1;i<=r1;i++){
            if(c[i]<=s[r1]-s[i])ans1=max(ans1,s[r1]-s[i]-c[i]);
        }
        //ans2=max(0ll,s[l2-1]-s[r1]);
        ans2=s[l2-1]-s[r1];
        for(int i=n;i>=l2;i--){
            if(abs(c[i])<=s[i-1]-s[l2-1])ans3=max(ans3,s[i-1]-s[l2-1]-abs(c[i]));
        }
        cout<<ans1+ans2+ans3<<endl;
    }
    return 0;
}
